// COMPLETE, COMPILABLE C++17 code
#include <bits/stdc++.h>
#include <boost/multiprecision/cpp_int.hpp>
using namespace std;
using boost::multiprecision::cpp_int;
const long long MOD = 998244353LL;

struct VecHash {
    size_t operator()(const vector<int>& v) const noexcept {
        size_t h = v.size();
        for (int x : v) h = h * 31 + x;
        return h;
    }
};

unordered_map<string, cpp_int> memo; // key = serialized sorted vector

string serialize(const vector<int>& v){
    string s;
    for(int x: v){s+=to_string(x)+',';}
    return s;
}

cpp_int dfs(vector<int> a){
    sort(a.begin(), a.end());
    string key = serialize(a);
    auto it = memo.find(key);
    if(it!=memo.end()) return it->second;
    // product if we stop now
    cpp_int best = 1;
    for(int x: a) best *= x;
    int n = a.size();
    // try all merges
    for(int i=0;i<n;i++){
        for(int j=i+1;j<n;j++){
            vector<int> b;
            b.reserve(n-1);
            for(int k=0;k<n;k++) if(k!=i && k!=j) b.push_back(a[k]);
            b.push_back(a[i]^a[j]);
            cpp_int cand = dfs(b);
            if(cand > best) best = cand;
        }
    }
    memo[key]=best;
    return best;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;cin>>T;
    while(T--){
        int N;cin>>N;
        vector<int> arr(N);
        for(int i=0;i<N;i++) cin>>arr[i];
        memo.clear();
        cpp_int ans = dfs(arr);
        long long out = (long long)(ans % MOD);
        cout<<out<<"\n";
    }
    return 0;
}

